mapper.select:
select p.*, u.real_name as seller_name, u.avatar as seller_avatar, c.category_name from product_info p left join sys_user u on p.seller_id = u.id left join product_category c on p.category_id = c.id where p.status = 'ON_SALE' and p.seller_id = #{sellerId}
and ( (#{sellerType} = 'PLANT' and p.seller_type in ('PLANT', 'PLANTER')) or (#{sellerType} = 'BREED' and p.seller_type in ('BREED', 'BREEDER')) or (#{sellerType} not in ('PLANT', 'BREED') and p.seller_type = #{sellerType}) )
order by p.sales_count desc, p.id desc
